package be.schaubroeck.lpb.rkm.rekenmotor.rsz.dmfa;

import be.schaubroeck.lpb.rkm.rekenmotor.rsz.IsPool2Ter;
import be.schaubroeck.lpb.rkm.rekenmotor.util.ConstantManager;
import be.schaubroeck.lpb.tools.Constant;
import be.schaubroeck.lpb.tools.enumtypes.Konstanten;
import be.schaubroeck.lpb.tools.enumtypes.Pensioenstelsel;
import be.schaubroeck.lpb.tools.rsz.CategorieKengetalStatuutPensioenstelsel;
import lombok.AllArgsConstructor;
import org.joda.time.LocalDate;

import java.util.EnumSet;

@AllArgsConstructor
public class IsPool2TerDmfa implements IsPool2Ter {

    private static final EnumSet<Pensioenstelsel> pool2TerPensioenstelsels = EnumSet.of(
            Pensioenstelsel.EIGEN_REGIME5,
            Pensioenstelsel.OMOB_REGIME3,
            Pensioenstelsel.OMOB_REGIME10);
    private final ConstantManager constantManager;

    public boolean check(CategorieKengetalStatuutPensioenstelsel categorieKengetalStatuutPensioenstelsel, LocalDate zoekDatum) {
        boolean isConstantePool2ter = isConstantePool2ter(zoekDatum);
        boolean isPool2ter = isPool2ter(categorieKengetalStatuutPensioenstelsel);
        return isConstantePool2ter && isPool2ter;
    }

    protected boolean isConstantePool2ter(LocalDate zoekDatum) {
        Constant pool2terConstante = constantManager.getByCodeDatumSafe(Konstanten.KST_POOL2TER.getCode(), zoekDatum);
        return pool2terConstante.getJaneen();
    }

    protected boolean isPool2ter(CategorieKengetalStatuutPensioenstelsel categorieKengetalStatuutPensioenstelsel) {
        boolean isVSpExngPct = categorieKengetalStatuutPensioenstelsel.isVSpExnhPct();
        boolean isPool2TerPensioenstelsel = isPool2TerPensioenstelsel(categorieKengetalStatuutPensioenstelsel);
        return isVSpExngPct && isPool2TerPensioenstelsel;
    }

    protected static boolean isPool2TerPensioenstelsel(CategorieKengetalStatuutPensioenstelsel categorieKengetalStatuutPensioenstelsel) {
        Pensioenstelsel pensioenStelsel = categorieKengetalStatuutPensioenstelsel.getPensioenStelsel();
        return pool2TerPensioenstelsels.contains(pensioenStelsel);
    }
}
